<script setup lang="ts">
import type { ServiceConfig } from '~/types'
import { useServices } from '~/composables/useServices'
import { useStatusStore } from '~/composables/useStatusStore'
import { usePolling } from '~/composables/usePolling'

useHead({ title: 'Dashboard — Status Concentrateur' })

const { enabledServices } = useServices()
const { currentStatus, getHistory } = useStatusStore()
const { loading, errors, startPolling, stopPolling, refreshService } = usePolling()

const selectedService = ref<ServiceConfig | null>(null)
const historyOpen = ref(false)

const globalLevel = computed(() => {
  const order = ['operational', 'maintenance', 'leger', 'mineur', 'majeur'] as const
  let worst = 0
  for (const svc of enabledServices.value) {
    const snap = currentStatus.value[svc.id]
    if (snap) {
      const idx = order.indexOf(snap.level as typeof order[number])
      if (idx > worst) worst = idx
    }
  }
  return order[worst]
})

const LEVEL_LABELS_GLOBAL: Record<string, string> = {
  operational: 'Tous les services opérationnels',
  leger: 'Légère perturbation détectée',
  mineur: 'Incident mineur en cours',
  majeur: 'Incident majeur en cours',
  maintenance: 'Maintenance en cours',
}

const GLOBAL_COLORS: Record<string, string> = {
  operational: 'bg-green-500',
  leger: 'bg-yellow-500',
  mineur: 'bg-orange-500',
  majeur: 'bg-red-500',
  maintenance: 'bg-blue-500',
}

function openHistory(service: ServiceConfig) {
  selectedService.value = service
  historyOpen.value = true
}

// Démarrer le polling sur mount
onMounted(() => {
  for (const svc of enabledServices.value) {
    startPolling(svc)
  }
})

// Réagir aux changements de services (ajout/suppression)
watch(enabledServices, (newList, oldList) => {
  const newIds = new Set(newList.map((s) => s.id))
  const oldIds = new Set(oldList.map((s) => s.id))

  for (const svc of newList) {
    if (!oldIds.has(svc.id)) startPolling(svc)
  }
  for (const svc of oldList) {
    if (!newIds.has(svc.id)) stopPolling(svc.id)
  }
}, { deep: true })

onUnmounted(() => {
  const { stopAll } = usePolling()
  stopAll()
})
</script>

<template>
  <div>
    <!-- Nav -->
    <nav class="bg-white border-b border-gray-100 sticky top-0 z-40">
      <div class="max-w-6xl mx-auto px-4 sm:px-6 h-14 flex items-center justify-between">
        <div class="flex items-center gap-3">
          <div class="w-7 h-7 rounded-lg bg-gray-900 flex items-center justify-center">
            <svg class="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
            </svg>
          </div>
          <span class="font-semibold text-gray-900">Status Dashboard</span>
        </div>

        <NuxtLink
          to="/services"
          class="flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-700 transition-colors"
        >
          <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          Gérer les services
        </NuxtLink>
      </div>
    </nav>

    <main class="max-w-6xl mx-auto px-4 sm:px-6 py-8">
      <!-- Global status banner -->
      <div
        class="rounded-2xl p-5 mb-8 flex items-center gap-4 text-white"
        :class="GLOBAL_COLORS[globalLevel]"
      >
        <div class="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center shrink-0">
          <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              v-if="globalLevel === 'operational'"
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width="2"
              d="M5 13l4 4L19 7"
            />
            <path
              v-else
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width="2"
              d="M12 9v2m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"
            />
          </svg>
        </div>
        <div>
          <p class="font-semibold text-lg">{{ LEVEL_LABELS_GLOBAL[globalLevel] }}</p>
          <p class="text-white/80 text-sm">{{ enabledServices.length }} service{{ enabledServices.length > 1 ? 's' : '' }} surveillé{{ enabledServices.length > 1 ? 's' : '' }}</p>
        </div>
      </div>

      <!-- Empty state -->
      <div v-if="enabledServices.length === 0" class="text-center py-20">
        <div class="w-16 h-16 rounded-2xl bg-gray-100 flex items-center justify-center mx-auto mb-4">
          <svg class="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
        </div>
        <h3 class="font-semibold text-gray-900 mb-1">Aucun service configuré</h3>
        <p class="text-gray-500 text-sm mb-5">Ajoutez des services pour commencer la surveillance</p>
        <NuxtLink
          to="/services"
          class="inline-flex items-center gap-2 px-4 py-2 bg-gray-900 text-white text-sm font-medium rounded-lg hover:bg-gray-700 transition-colors"
        >
          Gérer les services →
        </NuxtLink>
      </div>

      <!-- Services grid -->
      <div
        v-else
        class="grid gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3"
      >
        <ServiceCard
          v-for="svc in enabledServices"
          :key="svc.id"
          :service="svc"
          :snapshot="currentStatus[svc.id]"
          :loading="loading[svc.id]"
          :error="errors[svc.id]"
          @click="openHistory(svc)"
          @refresh="refreshService(svc)"
        />
      </div>
    </main>

    <!-- History modal -->
    <HistoryModal
      v-if="selectedService"
      :open="historyOpen"
      :service="selectedService"
      :snapshots="getHistory(selectedService.id)"
      @close="historyOpen = false"
    />
  </div>
</template>
