import { ref, onUnmounted } from 'vue'
import type { ServiceConfig, StatusSnapshot } from '~/types'
import { runAdapter } from '~/adapters/index'
import { useStatusStore } from './useStatusStore'

const loading = ref<Record<string, boolean>>({})
const errors = ref<Record<string, string | null>>({})

const timers = new Map<string, ReturnType<typeof setInterval>>()

async function fetchService(service: ServiceConfig) {
  loading.value[service.id] = true
  errors.value[service.id] = null

  try {
    const data = await $fetch('/api/proxy', {
      method: 'POST',
      body: {
        url: service.url,
        method: service.method,
        headers: service.headers,
        body: service.body,
      },
    })

    const result = runAdapter(service.adapter, data)

    const snapshot: StatusSnapshot = {
      serviceId: service.id,
      timestamp: new Date().toISOString(),
      level: result.level,
      message: result.message,
      incidents: result.incidents,
    }

    const { pushSnapshot } = useStatusStore()
    pushSnapshot(snapshot)
  }
  catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Erreur de récupération'
    errors.value[service.id] = msg

    // Push snapshot d'erreur pour garder la cohérence UI
    const { pushSnapshot } = useStatusStore()
    pushSnapshot({
      serviceId: service.id,
      timestamp: new Date().toISOString(),
      level: 'majeur',
      message: `Erreur: ${msg}`,
      incidents: [],
    })
  }
  finally {
    loading.value[service.id] = false
  }
}

function startPolling(service: ServiceConfig) {
  if (timers.has(service.id)) stopPolling(service.id)

  fetchService(service)

  const intervalMs = Math.min(service.pollInterval, 120) * 1000
  const timer = setInterval(() => fetchService(service), intervalMs)
  timers.set(service.id, timer)
}

function stopPolling(serviceId: string) {
  const timer = timers.get(serviceId)
  if (timer) {
    clearInterval(timer)
    timers.delete(serviceId)
  }
}

function stopAll() {
  timers.forEach((_, id) => stopPolling(id))
}

function refreshService(service: ServiceConfig) {
  fetchService(service)
}

export function usePolling() {
  return {
    loading,
    errors,
    startPolling,
    stopPolling,
    stopAll,
    refreshService,
    activePolls: timers,
  }
}
