<script setup lang="ts">
import type { ServiceConfig, StatusSnapshot } from '~/types'
import { LEVEL_COLORS } from '~/types'

const props = defineProps<{
  service: ServiceConfig
  snapshot?: StatusSnapshot
  loading?: boolean
  error?: string | null
}>()

const emit = defineEmits<{
  (e: 'click'): void
  (e: 'refresh'): void
}>()

const level = computed(() => props.snapshot?.level ?? 'operational')
const colors = computed(() => LEVEL_COLORS[level.value])

const lastUpdated = computed(() => {
  if (!props.snapshot?.timestamp) return null
  return new Date(props.snapshot.timestamp).toLocaleTimeString('fr-FR', {
    hour: '2-digit',
    minute: '2-digit',
  })
})

const incidentCount = computed(() => props.snapshot?.incidents?.length ?? 0)
</script>

<template>
  <button
    class="group w-full text-left rounded-xl border bg-white p-5 shadow-sm transition-all hover:shadow-md hover:-translate-y-0.5 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2"
    :class="[colors.border, `focus-visible:ring-${level === 'majeur' ? 'red' : level === 'mineur' ? 'orange' : level === 'leger' ? 'yellow' : level === 'maintenance' ? 'blue' : 'green'}-500`]"
    @click="emit('click')"
  >
    <!-- Header -->
    <div class="flex items-start justify-between gap-3">
      <div class="flex-1 min-w-0">
        <div class="flex items-center gap-2 mb-1">
          <h3 class="font-semibold text-gray-900 truncate">{{ service.name }}</h3>
          <span
            v-if="loading"
            class="inline-block w-3 h-3 rounded-full border-2 border-gray-300 border-t-gray-600 animate-spin"
          />
        </div>
        <StatusBadge :level="level" size="sm" />
      </div>

      <button
        class="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100"
        title="Rafraîchir"
        @click.stop="emit('refresh')"
      >
        <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
        </svg>
      </button>
    </div>

    <!-- Message -->
    <p class="mt-3 text-sm text-gray-600 line-clamp-2 min-h-[2.5rem]">
      <span v-if="error" class="text-red-600">{{ error }}</span>
      <span v-else-if="snapshot?.message">{{ snapshot.message }}</span>
      <span v-else class="text-gray-400 italic">En attente de données…</span>
    </p>

    <!-- Footer -->
    <div class="mt-3 flex items-center justify-between text-xs text-gray-400">
      <span v-if="incidentCount > 0" class="flex items-center gap-1">
        <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
        </svg>
        {{ incidentCount }} incident{{ incidentCount > 1 ? 's' : '' }}
      </span>
      <span v-else />

      <span v-if="lastUpdated">{{ lastUpdated }}</span>
    </div>
  </button>
</template>
